mapper.select:
SELECT ID, PURCHASE_TITLE, PURCHASE_NO, SUPPLIER_ID, SUPPLIER_NAME, PURCHASE_TYPE_CODE, PURCHASE_TYPE_NAME, FIXED_SERVICE_CATEGORY_CODE, FIXED_SERVICE_CATEGORY_NAME, TAX_INCLUDED_AMOUNT, TAX_EXCLUDED_AMOUNT, PURCHASE_STATUS, FAILURE_REASON, APPROVAL_BY, APPROVAL_BY_NAME, APPROVAL_TIME, APPROVAL_REMARK, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM E_MATERIAL_PURCHASE
AND PURCHASE_NO LIKE #{purchaseNoPattern}
AND PURCHASE_TITLE LIKE #{purchaseTitlePattern}
AND SUPPLIER_ID = #{supplierId}
AND SUPPLIER_NAME LIKE #{supplierNamePattern}
AND PURCHASE_TYPE_CODE = #{purchaseTypeCode}
AND PURCHASE_STATUS = #{purchaseStatus}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_PURCHASE
WHERE PURCHASE_NO = #{purchaseNo}

    AND ID != #{id}
